package node

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/veld-dev/veld/internal/ast"
)

// ExpressEmitter generates TypeScript types, service interfaces, and Express
// route files from a parsed AST.
type ExpressEmitter struct{}

// New returns an ExpressEmitter.
func New() *ExpressEmitter { return &ExpressEmitter{} }

// Emit writes all generated files into outDir.
func (e *ExpressEmitter) Emit(a ast.AST, outDir string) error {
	for _, mod := range a.Modules {
		if err := e.emitTypes(a, mod, outDir); err != nil {
			return fmt.Errorf("types for module %s: %w", mod.Name, err)
		}
		if err := e.emitInterface(a, mod, outDir); err != nil {
			return fmt.Errorf("interface for module %s: %w", mod.Name, err)
		}
		if err := e.emitRoutes(a, mod, outDir); err != nil {
			return fmt.Errorf("routes for module %s: %w", mod.Name, err)
		}
	}
	// Emit Zod validation schemas
	if err := e.emitZodSchemas(a, outDir); err != nil {
		return fmt.Errorf("zod schemas: %w", err)
	}
	return nil
}

// emitTypes writes generated/types/{module}.ts with TypeScript interfaces and enums.
func (e *ExpressEmitter) emitTypes(a ast.AST, mod ast.Module, outDir string) error {
	dir := filepath.Join(outDir, "types")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	usedNames := collectTransitiveModels(a, mod)
	usedEnums := collectUsedEnums(a, mod)

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n\n")

	// Emit enums used by this module
	for _, en := range a.Enums {
		if !usedEnums[en.Name] {
			continue
		}
		if en.Description != "" {
			sb.WriteString(fmt.Sprintf("/** %s */\n", en.Description))
		}
		quoted := make([]string, len(en.Values))
		for i, v := range en.Values {
			quoted[i] = fmt.Sprintf("\"%s\"", v)
		}
		sb.WriteString(fmt.Sprintf("export type %s = %s;\n\n", en.Name, strings.Join(quoted, " | ")))
	}

	for _, m := range a.Models {
		if !usedNames[m.Name] {
			continue
		}
		if m.Description != "" {
			sb.WriteString(fmt.Sprintf("/** %s */\n", m.Description))
		}
		sb.WriteString(fmt.Sprintf("export interface %s {\n", m.Name))
		for _, f := range m.Fields {
			tsType := veldTypeToTS(f.Type, f.IsArray)
			optMark := ""
			if f.Optional {
				optMark = "?"
			}
			sb.WriteString(fmt.Sprintf("  %s%s: %s;\n", f.Name, optMark, tsType))
		}
		sb.WriteString("}\n\n")
	}

	return os.WriteFile(filepath.Join(dir, strings.ToLower(mod.Name)+".ts"), []byte(sb.String()), 0644)
}

// emitInterface writes generated/interfaces/I{Module}Service.ts.
func (e *ExpressEmitter) emitInterface(a ast.AST, mod ast.Module, outDir string) error {
	dir := filepath.Join(outDir, "interfaces")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	moduleLower := strings.ToLower(mod.Name)
	usedTypes := collectUsedTypes(a, mod)

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	if len(usedTypes) > 0 {
		sb.WriteString(fmt.Sprintf("import type { %s } from '../types/%s';\n", strings.Join(usedTypes, ", "), moduleLower))
	}

	if mod.Description != "" {
		sb.WriteString(fmt.Sprintf("\n/** %s */\n", mod.Description))
	}
	sb.WriteString(fmt.Sprintf("\nexport interface I%sService {\n", mod.Name))
	for _, act := range mod.Actions {
		outputType := formatOutputType(act)
		if act.Description != "" {
			sb.WriteString(fmt.Sprintf("  /** %s */\n", act.Description))
		}
		if act.Input != "" && act.Query != "" {
			sb.WriteString(fmt.Sprintf("  %s(input: %s, query: %s): Promise<%s>;\n", act.Name, act.Input, act.Query, outputType))
		} else if act.Input != "" {
			sb.WriteString(fmt.Sprintf("  %s(input: %s): Promise<%s>;\n", act.Name, act.Input, outputType))
		} else if act.Query != "" {
			sb.WriteString(fmt.Sprintf("  %s(query: %s): Promise<%s>;\n", act.Name, act.Query, outputType))
		} else {
			sb.WriteString(fmt.Sprintf("  %s(userId: string): Promise<%s>;\n", act.Name, outputType))
		}
	}
	sb.WriteString("}\n")

	return os.WriteFile(filepath.Join(dir, fmt.Sprintf("I%sService.ts", mod.Name)), []byte(sb.String()), 0644)
}

// emitRoutes writes generated/routes/{module}.routes.ts.
func (e *ExpressEmitter) emitRoutes(_ ast.AST, mod ast.Module, outDir string) error {
	dir := filepath.Join(outDir, "routes")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	moduleLower := strings.ToLower(mod.Name)
	funcName := moduleLower + "Router"

	// Collect all unique middleware names used in this module.
	allMiddleware := collectModuleMiddleware(mod)

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString(fmt.Sprintf("import type { I%sService } from '../interfaces/I%sService';\n", mod.Name, mod.Name))

	// Emit a Middleware type so the caller knows exactly what to provide.
	if len(allMiddleware) > 0 {
		sb.WriteString("\n// Middleware functions your app must supply.\n")
		sb.WriteString("export interface Middleware {\n")
		for _, mw := range allMiddleware {
			sb.WriteString(fmt.Sprintf("  %s: (req: any, res: any, next: () => void) => void;\n", mw))
		}
		sb.WriteString("}\n")
	}

	sb.WriteString(fmt.Sprintf("\n// Pass any Express-compatible router, your service, and middleware implementations.\n"))
	if len(allMiddleware) > 0 {
		sb.WriteString(fmt.Sprintf("export function %s(router: any, service: I%sService, middleware: Middleware): void {\n", funcName, mod.Name))
	} else {
		sb.WriteString(fmt.Sprintf("export function %s(router: any, service: I%sService): void {\n", funcName, mod.Name))
	}

	for _, act := range mod.Actions {
		method := strings.ToLower(act.Method)
		routePath := act.Path
		if mod.Prefix != "" {
			routePath = mod.Prefix + act.Path
		}

		if act.Description != "" {
			sb.WriteString(fmt.Sprintf("\n  // %s\n", act.Description))
		}

		// Build the middleware chain: router.get('/path', mw1, mw2, handler)
		mwArgs := ""
		for _, mw := range act.Middleware {
			mwArgs += fmt.Sprintf("middleware.%s, ", mw)
		}

		sb.WriteString(fmt.Sprintf("\n  router.%s('%s', %sasync (req: any, res: any) => {\n", method, routePath, mwArgs))

		if act.Input != "" && act.Query != "" {
			sb.WriteString(fmt.Sprintf("    const result = await service.%s(req.body, req.query);\n", act.Name))
		} else if act.Input != "" {
			sb.WriteString(fmt.Sprintf("    const result = await service.%s(req.body);\n", act.Name))
		} else if act.Query != "" {
			sb.WriteString(fmt.Sprintf("    const result = await service.%s(req.query);\n", act.Name))
		} else {
			sb.WriteString(fmt.Sprintf("    const result = await service.%s(req.user?.id);\n", act.Name))
		}
		sb.WriteString("    res.json(result);\n")
		sb.WriteString("  });\n")
	}

	sb.WriteString("}\n")

	return os.WriteFile(filepath.Join(dir, moduleLower+".routes.ts"), []byte(sb.String()), 0644)
}

// collectModuleMiddleware returns all unique middleware names used in a module, in order of first appearance.
func collectModuleMiddleware(mod ast.Module) []string {
	seen := make(map[string]bool)
	var result []string
	for _, act := range mod.Actions {
		for _, mw := range act.Middleware {
			if !seen[mw] {
				seen[mw] = true
				result = append(result, mw)
			}
		}
	}
	return result
}

// emitZodSchemas writes generated/schemas/{module}.schema.ts with Zod validation schemas.
func (e *ExpressEmitter) emitZodSchemas(a ast.AST, outDir string) error {
	dir := filepath.Join(outDir, "schemas")
	if err := os.MkdirAll(dir, 0755); err != nil {
		return err
	}

	enumNames := make(map[string]bool)
	for _, en := range a.Enums {
		enumNames[en.Name] = true
	}

	var sb strings.Builder
	sb.WriteString("// AUTO-GENERATED BY VELD \u2014 DO NOT EDIT\n")
	sb.WriteString("import { z } from 'zod';\n\n")

	// Emit enum schemas
	for _, en := range a.Enums {
		if en.Description != "" {
			sb.WriteString(fmt.Sprintf("/** %s */\n", en.Description))
		}
		quoted := make([]string, len(en.Values))
		for i, v := range en.Values {
			quoted[i] = fmt.Sprintf("'%s'", v)
		}
		sb.WriteString(fmt.Sprintf("export const %sSchema = z.enum([%s]);\n\n", en.Name, strings.Join(quoted, ", ")))
	}

	// Emit model schemas
	for _, m := range a.Models {
		if m.Description != "" {
			sb.WriteString(fmt.Sprintf("/** %s */\n", m.Description))
		}
		sb.WriteString(fmt.Sprintf("export const %sSchema = z.object({\n", m.Name))
		for _, f := range m.Fields {
			zodType := veldTypeToZod(f.Type, f.IsArray, enumNames)
			if f.Default != "" {
				defaultVal := f.Default
				// Enum and string defaults that aren't already quoted need quoting in JS
				if !strings.HasPrefix(defaultVal, "\"") && defaultVal != "true" && defaultVal != "false" && !isNumericDefault(defaultVal) {
					defaultVal = "'" + defaultVal + "'"
				} else if strings.HasPrefix(defaultVal, "\"") {
					// Replace Go-style "val" with JS-style 'val'
					defaultVal = "'" + strings.Trim(defaultVal, "\"") + "'"
				}
				zodType += fmt.Sprintf(".default(%s)", defaultVal)
			}
			if f.Optional && f.Default == "" {
				zodType += ".optional()"
			}
			sb.WriteString(fmt.Sprintf("  %s: %s,\n", f.Name, zodType))
		}
		sb.WriteString("});\n\n")
	}

	return os.WriteFile(filepath.Join(dir, "schemas.ts"), []byte(sb.String()), 0644)
}

// formatOutputType returns the TS type for an action output, handling arrays.
func formatOutputType(act ast.Action) string {
	if act.OutputArray {
		return veldScalarToTS(act.Output) + "[]"
	}
	return veldScalarToTS(act.Output)
}

// collectTransitiveModels returns all model names needed by a module, following
// array element types and other model references in fields.
func collectTransitiveModels(a ast.AST, mod ast.Module) map[string]bool {
	byName := make(map[string]ast.Model, len(a.Models))
	for _, m := range a.Models {
		byName[m.Name] = m
	}

	used := make(map[string]bool)
	queue := []string{}
	for _, act := range mod.Actions {
		if act.Input != "" {
			queue = append(queue, act.Input)
		}
		if act.Output != "" {
			queue = append(queue, act.Output)
		}
		if act.Query != "" {
			queue = append(queue, act.Query)
		}
	}
	for len(queue) > 0 {
		name := queue[0]
		queue = queue[1:]
		if used[name] {
			continue
		}
		used[name] = true
		if m, ok := byName[name]; ok {
			for _, f := range m.Fields {
				base := f.Type
				if _, isModel := byName[base]; isModel && !used[base] {
					queue = append(queue, base)
				}
			}
		}
	}
	return used
}

// collectUsedEnums returns the set of enum names referenced by models used in a module.
func collectUsedEnums(a ast.AST, mod ast.Module) map[string]bool {
	enumNames := make(map[string]bool)
	for _, en := range a.Enums {
		enumNames[en.Name] = true
	}

	usedModels := collectTransitiveModels(a, mod)
	usedEnums := make(map[string]bool)

	for _, m := range a.Models {
		if !usedModels[m.Name] {
			continue
		}
		for _, f := range m.Fields {
			if enumNames[f.Type] {
				usedEnums[f.Type] = true
			}
		}
	}
	return usedEnums
}

// collectUsedTypes returns the unique type names referenced as inputs, outputs,
// or queries in the module, including enums.
func collectUsedTypes(a ast.AST, mod ast.Module) []string {
	seen := make(map[string]bool)
	var result []string

	enumNames := make(map[string]bool)
	for _, en := range a.Enums {
		enumNames[en.Name] = true
	}

	// Collect model names used directly in actions
	for _, act := range mod.Actions {
		for _, name := range []string{act.Input, act.Output, act.Query} {
			if name != "" && !seen[name] && !isPrimitive(name) {
				seen[name] = true
				result = append(result, name)
			}
		}
	}

	// Also collect types referenced in model fields (transitively)
	usedModels := collectTransitiveModels(a, mod)
	byName := make(map[string]ast.Model, len(a.Models))
	for _, m := range a.Models {
		byName[m.Name] = m
	}
	for _, m := range a.Models {
		if !usedModels[m.Name] {
			continue
		}
		if !seen[m.Name] {
			seen[m.Name] = true
			result = append(result, m.Name)
		}
		for _, f := range m.Fields {
			base := f.Type
			if _, isModel := byName[base]; isModel && !seen[base] {
				seen[base] = true
				result = append(result, base)
			}
			if enumNames[base] && !seen[base] {
				seen[base] = true
				result = append(result, base)
			}
		}
	}

	// Collect used enums
	usedEnums := collectUsedEnums(a, mod)
	for _, en := range a.Enums {
		if usedEnums[en.Name] && !seen[en.Name] {
			seen[en.Name] = true
			result = append(result, en.Name)
		}
	}

	return result
}

func isPrimitive(t string) bool {
	switch t {
	case "string", "int", "float", "bool", "date", "datetime", "uuid":
		return true
	}
	return false
}

// isNumericDefault returns true if the default value string looks like a number.
func isNumericDefault(s string) bool {
	if len(s) == 0 {
		return false
	}
	start := 0
	if s[0] == '-' {
		start = 1
	}
	if start >= len(s) {
		return false
	}
	for i := start; i < len(s); i++ {
		if (s[i] < '0' || s[i] > '9') && s[i] != '.' {
			return false
		}
	}
	return true
}

// veldScalarToTS maps a Veld scalar or model name to TS.
func veldScalarToTS(t string) string {
	switch t {
	case "int", "float":
		return "number"
	case "bool":
		return "boolean"
	case "date", "datetime", "uuid":
		return "string"
	default:
		return t // model/enum reference stays as-is
	}
}

// veldTypeToTS maps a Veld type name to its TypeScript equivalent.
// Handles array: isArray=true → Type[]
func veldTypeToTS(t string, isArray bool) string {
	base := veldScalarToTS(t)
	if isArray {
		return base + "[]"
	}
	return base
}

// veldTypeToZod maps a Veld type name to its Zod equivalent.
func veldTypeToZod(t string, isArray bool, enumNames map[string]bool) string {
	var base string
	switch t {
	case "string":
		base = "z.string()"
	case "int":
		base = "z.number().int()"
	case "float":
		base = "z.number()"
	case "bool":
		base = "z.boolean()"
	case "date":
		base = "z.string().date()"
	case "datetime":
		base = "z.string().datetime()"
	case "uuid":
		base = "z.string().uuid()"
	default:
		if enumNames[t] {
			base = fmt.Sprintf("%sSchema", t)
		} else {
			base = fmt.Sprintf("%sSchema", t)
		}
	}
	if isArray {
		return fmt.Sprintf("z.array(%s)", base)
	}
	return base
}
